import{_ as t,o as e,c as a,a4 as o}from"./chunks/framework.BMymQDdR.js";const b=JSON.parse('{"title":"构建与运行","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Build-Run.md","filePath":"zh/v3/designer/Build-Run.md","lastUpdated":1780630099000}'),d={name:"v3/designer/Build-Run.md"},r=o('<h1 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h1><p>ENERGY Designer 提供完整的构建和运行预览功能，支持编译项目、清理构建产物、一键运行预览。</p><h2 id="运行预览" tabindex="-1">运行预览 <a class="header-anchor" href="#运行预览" aria-label="Permalink to &quot;运行预览&quot;">​</a></h2><p>通过 <strong>运行 &gt; 运行预览</strong>（快捷键 <code>F9</code>）或工具栏的运行按钮，可一键编译并运行当前项目进行预览。</p><h3 id="运行流程" tabindex="-1">运行流程 <a class="header-anchor" href="#运行流程" aria-label="Permalink to &quot;运行流程&quot;">​</a></h3><ol><li><strong>编译项目</strong> - 自动执行 <code>go build</code> 编译当前项目</li><li><strong>打包应用</strong> - macOS 平台自动创建 <code>.app</code> 包并签名</li><li><strong>启动预览</strong> - 运行编译后的可执行文件</li><li><strong>实时输出</strong> - 构建和运行日志输出到日志控制台</li></ol><h3 id="运行状态" tabindex="-1">运行状态 <a class="header-anchor" href="#运行状态" aria-label="Permalink to &quot;运行状态&quot;">​</a></h3><p>运行按钮在不同状态间切换：</p><table tabindex="0"><thead><tr><th>状态</th><th>按钮显示</th><th>说明</th></tr></thead><tbody><tr><td>未运行</td><td>运行图标</td><td>点击开始运行预览</td></tr><tr><td>启动中</td><td>停止图标（禁用）</td><td>正在编译，暂不可操作</td></tr><tr><td>运行中</td><td>停止图标</td><td>点击停止运行预览</td></tr></tbody></table><h3 id="停止预览" tabindex="-1">停止预览 <a class="header-anchor" href="#停止预览" aria-label="Permalink to &quot;停止预览&quot;">​</a></h3><p>运行预览期间，点击 <strong>停止</strong> 按钮或再次按 <code>F9</code> 可终止预览进程。</p><h2 id="构建" tabindex="-1">构建 <a class="header-anchor" href="#构建" aria-label="Permalink to &quot;构建&quot;">​</a></h2><p>通过 <strong>运行 &gt; 构建</strong>（快捷键 <code>Ctrl+F8</code> / macOS <code>Cmd+F8</code>）执行项目编译。</p><h3 id="构建过程" tabindex="-1">构建过程 <a class="header-anchor" href="#构建过程" aria-label="Permalink to &quot;构建过程&quot;">​</a></h3><ol><li>读取项目构建配置</li><li>设置编译环境变量</li><li>执行 <code>go build</code> 命令</li><li>输出编译结果到日志控制台</li></ol><p>构建期间，菜单栏和工具栏的功能按钮暂时禁用，防止误操作。构建完成后自动恢复。</p><h2 id="清理构建" tabindex="-1">清理构建 <a class="header-anchor" href="#清理构建" aria-label="Permalink to &quot;清理构建&quot;">​</a></h2><p>通过 <strong>运行 &gt; 清理构建</strong>（快捷键 <code>Ctrl+Shift+F8</code> / macOS <code>Cmd+Shift+F8</code>）清理构建产物。</p><p>清理操作会删除 <code>build/</code> 目录下的编译输出文件。</p><h2 id="构建所有" tabindex="-1">构建所有 <a class="header-anchor" href="#构建所有" aria-label="Permalink to &quot;构建所有&quot;">​</a></h2><p>通过 <strong>运行 &gt; 构建所有</strong>（快捷键 <code>Ctrl+Shift+F9</code> / macOS <code>Cmd+Shift+F9</code>）执行全量构建，包含所有平台和架构的编译。</p><h2 id="日志输出" tabindex="-1">日志输出 <a class="header-anchor" href="#日志输出" aria-label="Permalink to &quot;日志输出&quot;">​</a></h2><p>构建和运行过程中的所有输出（包括编译错误、运行日志等）会实时显示在底部的 <strong>日志控制台</strong> 中，方便排查问题。</p><p>日志按级别以不同颜色显示：</p><ul><li><strong>红色</strong> - 错误信息 (<code>[ERROR]</code>)</li><li><strong>蓝色</strong> - 警告信息 (<code>[WARN]</code>)</li><li><strong>绿色</strong> - 普通信息 (<code>[INFO]</code>)</li><li><strong>灰色</strong> - 调试信息 (<code>[DEBUG]</code>)</li></ul>',25),i=[r];function l(n,c,s,h,g,u){return e(),a("div",null,i)}const _=t(d,[["render",l]]);export{b as __pageData,_ as default};
